function slugify(value:string){return value.normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,"");}
function sourceSlug(entity:ContentEntity){return entity.versions.en?.publicPath?.split("/").filter(Boolean).pop() ?? entity.id;}
function category(entity:ContentEntity){const p=entity.versions.en?.publicPath??"";return p.includes("/dumbbells/")?"manubri":p.includes("/weight-plates/")?"dischi-pesi":p.includes("/racks-benches/")?"rack-panche":"accessori-palestra";}
function productName(entity:ContentEntity){return productNames[sourceSlug(entity)] ?? "Attrezzatura fitness professionale";}
function productPath(entity:ContentEntity,name:string){return `/it/prodotti/${category(entity)}/${slugify(name)}`;}
