function sourceImages(entity:ContentEntity,slug:string):LocalizedImage[]{const existing=entity.versions.en?.images??[];const sources=[existing[0]?.src??productImageFallback[sourceSlug(entity)],"/assets/dumbbell-production.webp","/assets/resource-plate-finishing.webp"].filter((value):value is string=>Boolean(value));return sources.slice(0,3).map((src,index)=>({id:`immagine-${index+1}`,src:italianImagePath(src,slug,index),alt:index===0?`${productName(entity)} per palestra professionale`:index===1?`Fase reale di produzione relativa a ${productName(entity).toLowerCase()}`:`Controllo reale della finitura di ${productName(entity).toLowerCase()}`,caption:index===0?"Immagine reale del prodotto PowerBaseFit; configurazione finale secondo offerta approvata.":index===1?"Fase reale di lavorazione nello stabilimento PowerBaseFit.":"Verifica reale di superficie e finitura prima dell'imballaggio."}));}

const variantNotes=[
  "Prepara una tavola fotografica con vista, scala e illuminazione costanti. Associa ogni immagine a codice e revisione: il confronto visivo diventa così ripetibile e non dipende dalla memoria di chi ha approvato il primo campione.",
  "Chiedi un diagramma semplice dei punti critici e assegna a ciascuno controllo, frequenza e registrazione. Questa mappa mostra dove una deviazione può essere intercettata prima che il valore venga incorporato nel prodotto finito.",
  "Esegui una prova di ricezione con personale e attrezzatura disponibili nel magazzino previsto. Tempo, peso del collo, accesso e smaltimento delle protezioni rivelano costi operativi che il prezzo fabbrica non mostra.",
  "Definisci un campione limite per i difetti estetici più discussi. Affiancare un esempio accettabile e uno respinto riduce interpretazioni su graffi, variazioni di tono, linee di giunzione o piccole irregolarità superficiali.",
  "Crea una matrice di responsabilità tra buyer, produttore, ispettore, spedizioniere e magazzino. Ogni passaggio deve avere input, decisione e prova, evitando che un'attività critica resti implicitamente affidata a due parti o a nessuna.",
  "Verifica la prima unità dopo cambio di materiale, utensile o turno e confrontala con il riferimento approvato. Un controllo anticipato costa meno della selezione di un lotto già completato e rende visibile la causa della variazione.",
  "Attribuisci un codice distinto a ogni variante vendibile, anche quando la differenza è soltanto colore o logo. Ordine, etichetta, cartone, packing list e rapporto QC devono usare lo stesso identificatore senza abbreviazioni locali.",
  "Simula il riordino usando soltanto i documenti archiviati. Se il team non riesce a ricostruire configurazione, artwork e imballaggio senza messaggi privati, il fascicolo prodotto non è ancora sufficiente a garantire continuità.",
  "Concorda come viene gestita una deviazione proposta dal produttore: motivazione, impatto, campione o prova, approvazione scritta e aggiornamento dei documenti. La sostituzione silenziosa non deve diventare una scorciatoia di pianificazione.",
  "Separa le misure che influenzano funzione da quelle puramente informative. Le prime richiedono limite e metodo; le seconde aiutano catalogo e logistica. Questa distinzione concentra tempo di controllo dove una variazione produce conseguenze reali.",
  "Raccogli dati dopo trenta, novanta e centottanta giorni di utilizzo quando il progetto lo consente. Segni, allentamenti, problemi di pulizia o ricambi vengono collegati a batch e condizioni, trasformando esperienza operativa in requisito futuro.",
  "Confronta il costo per unità vendibile, non soltanto per unità prodotta. Aggiungi scarti, danni, pezzi mancanti e rilavorazioni osservati nello scenario; un'alternativa più costosa all'origine può generare margine migliore dopo la consegna.",
  "Per una gamma coordinata stabilisci quali caratteristiche devono essere identiche e quali possono variare per modello. Colore, carattere, marcatura e proporzioni possono richiedere una regola di famiglia anche quando costruzione e misure sono diverse.",
  "Controlla che manuale, etichetta e contenuto del cartone descrivano la stessa configurazione. Una revisione tecnica corretta con istruzioni precedenti può causare montaggio errato, reclamo o necessità di ristampa nel paese di destinazione.",
  "Prevedi una finestra per rilavorazione e nuova ispezione nel calendario. Se il piano presuppone conformità perfetta al primo tentativo, qualsiasi deviazione trasforma un problema gestibile in ritardo di spedizione o decisione commerciale affrettata.",
  "Indica nel verbale quali dati sono misurati, calcolati, dichiarati o stimati. La distinzione permette di aggiornare il modello quando arrivano campione, packing list o offerta di trasporto senza perdere la storia delle ipotesi precedenti.",
  "Usa una riunione di pre-produzione breve ma strutturata: versione, materiali, punti estetici, logo, cartone, test e date. Il verbale firmato o confermato diventa riferimento comune per commerciale, fabbrica, qualità e buyer.",
  "Verifica l'accessibilità dei componenti che richiedono pulizia, regolazione o sostituzione. Una costruzione può funzionare bene al collaudo ma generare fermo e costo se la manutenzione ordinaria richiede smontaggi non previsti.",
  "Durante il carico controlla numero e condizione dei pallet, sigilli e corrispondenza con i documenti. Registrare l'ultimo passaggio riduce l'area grigia tra ispezione completata e presa in carico del trasporto.",
  "Definisci il criterio di chiusura del progetto: documenti approvati, campione archiviato, rapporto accettato, saldo autorizzato e file di riordino completo. Senza chiusura formale, domande irrisolte riappaiono alla consegna successiva."
];
function uniqueNotes(key:string,subject:string,id="note-specifiche"){let hash=2166136261;for(const char of key)hash=Math.imul(hash^char.charCodeAt(0),16777619)>>>0;const first=hash%variantNotes.length;let second=Math.floor(hash/variantNotes.length)%variantNotes.length;if(second===first)second=(second+7)%variantNotes.length;return itText(id,"Note operative dedicate",`${subject}: ${variantNotes[first]}`,variantNotes[second]);}

function base(version:Omit<LocalizedContentVersion,"locale"|"translationStatus"|"reviewStatus"|"publishStatus"|"canonicalData"|"hreflangData"|"updatedAt"|"publishedAt"|"version">):LocalizedContentVersion{return{...version,locale:"it",translationStatus:"localized",reviewStatus:"approved",publishStatus:"published",canonicalData:{mode:"self"},hreflangData:{include:true},updatedAt:publishedAt,publishedAt,version:1};}

function coreVersion(entity:ContentEntity,profile:(typeof core)[string]):LocalizedContentVersion{
  const slug=profile.path.split("/").filter(Boolean).pop()??"italia";const first=entity.versions.en?.images[0]?.src??"/assets/homepage-concept.webp";
  const images=[first,"/assets/dumbbell-production.webp","/assets/factory-cases/packaging-area-pbf.webp"].map((src,index)=>({id:`immagine-${index+1}`,src:italianImagePath(src,slug,index),alt:index===0?`${profile.h1} — immagine reale PowerBaseFit`:index===1?"Produzione reale di attrezzature fitness PowerBaseFit":"Imballaggio export reale per attrezzature palestra",caption:index===0?"Immagine esistente della gamma o dell'attività PowerBaseFit.":index===1?"Una fase reale del processo produttivo.":"Preparazione reale dell'imballaggio per la spedizione."}));
  const body=[itAnswer("risposta","Risposta chiara",`PowerBaseFit supporta acquirenti professionali che devono ${profile.role}. Il lavoro parte da utilizzo, quantità, configurazione e destinazione; prosegue con fattibilità, offerta, campione quando necessario, controllo qualità e documenti di spedizione.`),itDefinition("definizione",profile.keyword,`${profile.keyword} indica una ricerca con intento professionale: il compratore non cerca soltanto un articolo, ma un fornitore capace di collegare prodotto, specifica, qualità, personalizzazione e consegna.`),itText("mercato","Cosa conta per un acquirente italiano","Qualità, durata e affidabilità devono essere dimostrate con dati riferiti alla versione acquistata. Foto generiche o promesse commerciali non sostituiscono materiale, misure, tolleranze, campione e piano di controllo.","Per distributori e importatori italiani contano anche continuità del riordino, identificazione degli SKU, imballaggio, peso lordo, volume e chiarezza dell'Incoterm. Per una palestra o un progetto commerciale diventano centrali utilizzo, flusso, spazio e manutenzione."),itTable("processo","Percorso B2B verificabile",["Fase","Decisione","Risultato"],[["Brief","Uso, gamma, quantità, destinazione","Requisiti iniziali"],["Fattibilità","Materiali, misure, personalizzazione","Configurazione quotabile"],["Campione","Aspetto, funzione, marcatura","Riferimento approvato"],["Produzione","Processo e controlli intermedi","Lotto tracciabile"],["Spedizione","Ispezione, imballaggio, documenti","Ordine pronto alla consegna"]]),itText("qualita","Qualità, durata e affidabilità","La qualità si definisce prima dell'ordine: caratteristiche critiche, metodo di verifica, campionamento e responsabilità. Durante la produzione i controlli devono seguire la famiglia di prodotto; prima della spedizione il lotto viene confrontato con specifica e riferimento approvato.","La durata non può essere riassunta in un aggettivo. Dipende da materiale, costruzione, finitura, carico, frequenza d'uso, pavimento, pulizia e manutenzione. Il preventivo deve chiarire quali condizioni sono state considerate."),itText("personalizzazione","OEM, ODM e marchio privato","Logo, colore, marcatura del peso, etichetta e cartone vengono valutati come un unico sistema. Metodo, posizione, dimensione, file grafico, MOQ ed eventuale campione sono confermati prima della serie.","Un progetto ODM comporta modifiche più profonde rispetto a un'applicazione di logo. Disegni, utensili, responsabilità tecniche, prove e gestione delle revisioni devono quindi essere espliciti."),itChecklist("checklist","Checklist prima della richiesta di offerta",["Definire cliente target e ambiente d'uso","Elencare articoli e quantità per variante","Indicare misure, pesi e materiali essenziali","Separare requisiti obbligatori e preferenze","Allegare logo e guida del marchio","Definire tipo di campione e approvazione","Indicare imballaggio, destinazione e Incoterm","Chiedere peso netto, lordo e volume","Concordare controlli e gestione delle non conformità","Archiviare versione e riferimento per il riordino"]),itText("preventivo","Come ottenere un preventivo utilizzabile","Una quotazione confrontabile richiede la stessa base per tutti i fornitori. Quantità, personalizzazione, imballaggio e punto di consegna devono essere espliciti; costi una tantum come campione o utensile vanno separati dal prezzo unitario.","Se un dato critico manca, è più corretto registrarlo come ipotesi aperta. In questo modo il compratore sa quali variabili possono cambiare prezzo, MOQ o lead time prima dell'approvazione finale."),itText("responsabilita","Importazione e responsabilità di mercato","L'importatore italiano deve verificare classificazione doganale, valore, dazi, IVA e obblighi applicabili al prodotto e al modo in cui viene commercializzato. Le informazioni del fornitore sono un input, non sostituiscono la valutazione aggiornata di professionisti e autorità competenti.","Per la Svizzera italiana cambiano autorità, procedure e imposizione: il paese di immissione sul mercato deve essere indicato nel brief, evitando di trattare Italia e Svizzera come un unico scenario amministrativo."),itText("prossimo-passo","Il prossimo passo",`Per ${profile.role}, invia la categoria, la quantità indicativa, il livello di personalizzazione, la destinazione e la data obiettivo. PowerBaseFit può quindi evidenziare le decisioni che influenzano fattibilità, MOQ, campione, controllo e consegna.`)];
  if(entity.id==="contact")body.splice(7,0,{id:"richiesta",type:"custom",heading:"Invia i dati del progetto",data:{component:"inquiry-form"}});
  return base({slug,publicPath:profile.path,title:profile.title,description:profile.description,h1:profile.h1,body,faq:[{id:"faq-1",question:"PowerBaseFit lavora con clienti B2B?",answer:"Sì. Il sito italiano è rivolto a distributori, importatori, brand fitness, palestre e progetti commerciali con quantità e specifiche professionali."},{id:"faq-2",question:"È possibile personalizzare logo e imballaggio?",answer:"Sì, per prodotti e quantità compatibili. Metodo, MOQ, file grafici e campione vengono confermati prima della produzione."},{id:"faq-3",question:"Quali dati servono per il preventivo?",answer:"Prodotto, quantità per variante, uso, personalizzazione, imballaggio, destinazione, Incoterm e tempistica desiderata."},{id:"faq-4",question:"È possibile organizzare un'ispezione indipendente?",answer:"Sì, quando criteri, campionamento, accesso e momento dell'ispezione sono concordati prima della produzione."}],author:italianEditorialAuthor,reviewedBy:italianTechnicalReviewer,schemaData:{brand:"PowerBaseFit",manufacturer:"PowerBaseFit",category:profile.keyword,specifications:[{name:"Tema principale",value:profile.keyword},{name:"Mercato",value:"Italia e acquirenti B2B italofoni"}],breadcrumbs:[{name:"Home",path:"/it"},...(profile.path==="/it"?[]:[{name:profile.h1,path:profile.path}])],extra:{primaryKeyword:profile.keyword,searchIntent:profile.role}},images,internalLinks:[{targetContentId:"products-hub",label:"Esplora i prodotti"},{targetContentId:"factory",label:"Produzione e controllo qualità"},{targetContentId:"oem-private-label",label:"OEM e marchio privato"},{targetContentId:"contact",label:"Richiedi un preventivo"}]});
}

function productExpansion(entity:ContentEntity,name:string){
  const slug=sourceSlug(entity);
  const material=/cpu/i.test(slug)?"Per il CPU vanno chiariti formulazione, metodo di colata o rivestimento, adesione al nucleo, durezza quando pertinente e stabilità cromatica. Il campione deve essere rappresentativo del processo previsto per la serie; una finitura ottenuta con un ciclo diverso non qualifica automaticamente il lotto.":/tpu/i.test(slug)?"Per il TPU il buyer verifica composizione della parte rivestita, uniformità della superficie, comportamento su bordi e marcature e possibilità di mantenere colore e texture nel riordino. La denominazione del polimero non sostituisce una prova sulla costruzione completa.":/(?:^|-)pu(?:-|$)/i.test(slug)?"Per il PU occorre distinguere materiale del rivestimento, nucleo e metodo di legame. Colore, lucentezza, bolle, linee di giunzione e protezione delle zone di presa vengono approvati con limiti visivi e riferimenti fisici coerenti con il posizionamento della gamma.":/rubber/i.test(slug)?"Per la gomma contano miscela, odore, texture, adesione e protezione delle superfici a contatto. Valuta il campione dopo pulizia e movimentazione realistiche, definendo quali segni sono accettabili e come il materiale viene separato nel cartone durante il trasporto.":/steel|sus304|aluminum/i.test(slug)?"Per i componenti metallici il buyer specifica grado o dichiarazione materiale quando necessaria, lavorazione, finitura, bordi e protezione dalla corrosione. Misure funzionali e accoppiamenti vengono controllati dopo il trattamento superficiale, perché rivestimento e lucidatura possono modificare il risultato finale.":/cast-iron/i.test(slug)?"Per la ghisa si controllano fusione, geometria, lavorazioni successive, massa e finitura. Porosità, bordi, planarità e protezione superficiale devono avere criteri proporzionati all'uso; una verniciatura gradevole non compensa un foro o un appoggio fuori specifica.":"Il materiale deve essere definito per ciascun componente critico e collegato alla funzione prevista. Il campione permette di verificare tatto, finitura e interfacce, mentre i controlli del lotto dimostrano che la configurazione può essere ripetuta.";
  const form=/adjustable|selectorized/i.test(slug)?"Per un modello regolabile, oltre a peso e dimensioni, verifica selezione, blocco, rilascio, indicazione del carico e comportamento dopo cicli ripetuti. Supporto e unità devono essere provati insieme, includendo uso scorretto ragionevolmente prevedibile nel piano di valutazione.":/hexagonal|hex-dumbbell/i.test(slug)?"La geometria esagonale limita il rotolamento ma richiede controllo di allineamento, stabilità e larghezza delle teste. Prova appoggio a terra e compatibilità con la rastrelliera reale; facce non parallele o dimensioni variabili possono ridurre ordine visivo e facilità di presa.":/round/i.test(slug)?"La forma rotonda deve essere valutata insieme alla rastrelliera, perché diametro e larghezza cambiano spazio, appoggio e accesso. Controlla simmetria, marcatura e comportamento quando il manubrio viene riposto, evitando che il bordo danneggi prodotti vicini.":/bench/i.test(slug)?"Per la panca sono centrali impronta, angoli, stabilità, imbottitura, regolazioni e punti di presa. Il campione completo deve essere montato e azionato; gioco, allineamento, piedini e accesso ai perni si controllano nelle posizioni realmente offerte.":/rack|smith|trainer|cable|machine|jungle|frame/i.test(slug)?"Per strutture e stazioni si definiscono ingombro, area operativa, telaio, giunzioni, cavi, pulegge, regolazioni, protezioni e montaggio. Il responsabile locale verifica pavimento e ancoraggi; il fornitore deve identificare componenti, minuteria e ricambi nella distinta e nel packaging.":/plate/i.test(slug)?"Per un disco si misurano massa, diametro, spessore, foro, planarità e interfaccia con il bilanciere. Se l'uso prevede impatto, la prova deve dichiarare superficie e cicli; se sono presenti prese, si controllano dimensione, bordi e resistenza della zona di impugnatura.":/handle|attachment|bar|rope/i.test(slug)?"Per un accessorio da cavo la compatibilità nasce da misure reali di attacco, spazio di movimento, presa e carico previsto. Giunti, saldature o terminali sono ispezionati prima e dopo la prova; lunghezza e geometria devono essere coerenti con le macchine del cliente.":"La geometria va collegata a utilizzo, stoccaggio e manutenzione. Misure, interfacce e punti di contatto vengono verificati su un campione completo, senza dedurre la compatibilità soltanto dal nome commerciale.";
  const logistics=[
    "Per questo articolo pianifica un campione dall'estremo più sollecitato della gamma e conserva fotografia, misure e peso lordo del cartone. Nel riordino confronta i primi pezzi con quei dati prima di autorizzare l'intero lotto.",
    "La RFQ deve indicare unità di vendita, quantità per variante e modalità di esposizione. Verifica che etichetta e codice distinguano versioni simili, riducendo errori di picking nel magazzino del distributore.",
    "Simula ricezione e apertura del collo: peso, presa, protezioni e sequenza di rimozione incidono su danni e tempo operativo. Registra il risultato del primo ordine per correggere il packaging successivo.",
    "Se il prodotto entra in una linea esistente, confronta colore, proporzioni, marcatura e sistema di stoccaggio con gli articoli già a catalogo. Una variante tecnicamente valida può essere commercialmente incoerente.",
    "Per un progetto palestra, lega quantità e posizione alla planimetria. Passaggi, area d'uso, manutenzione e accesso non devono essere dedotti dall'ingombro esterno riportato in una singola vista del prodotto.",
    "Nel calcolo economico separa prezzo ricorrente da campione, utensile, grafica e ricambi. Distribuire un costo una tantum sul primo ordine senza evidenziarlo rende fuorviante il confronto con il riordino.",
    "Definisci una parte di ricambio o una procedura di sostituzione quando il prodotto contiene componenti soggetti a usura. Codici e revisione devono permettere di fornire il componente corretto senza sostituire l'intera unità.",
    "Prima del carico confronta quantità fisica, packing list e marcatura dei colli. Fotografa pallet identificati e registra deviazioni: la tracciabilità logistica completa il controllo di prodotto, non lo sostituisce."
  ];
  let hash=0;for(const char of slug)hash=(hash*31+char.charCodeAt(0))>>>0;
  return[itText("approfondimento-prodotto",`Punti tecnici specifici per ${name}`,material,form,logistics[hash%logistics.length]),uniqueNotes(slug,name),uniqueNotes([...slug].reverse().join(""),name,"verifica-dedicata")];
}

function productVersion(entity:ContentEntity):LocalizedContentVersion{
  const name=productName(entity),slug=slugify(name),path=productPath(entity,name),family=category(entity),material=/CPU|TPU|PU|gomma|ghisa|acciaio|neoprene|vinile|alluminio|TPE/.exec(name)?.[0]??"materiale definito nella specifica";const images=sourceImages(entity,slug);
  const body=[itAnswer("risposta","Risposta rapida",`${name} è una soluzione destinata a palestre, distributori e brand che richiedono una configurazione ripetibile, dati di prodotto chiari e possibilità OEM. La scelta corretta dipende da utilizzo, gamma, quantità, finitura, imballaggio e destinazione, non soltanto dal prezzo unitario.`),itDefinition("definizione",name,`${name} appartiene alla categoria ${family.replace("-"," ")} e viene valutato come componente di un assortimento professionale. Materiale, geometria, peso o portata, interfacce, finitura e marcatura devono essere coerenti tra campione, lotto e riordino.`),itText("posizionamento","Posizionamento e applicazioni",`Il prodotto è indicato per operatori che devono costruire o ampliare un'offerta di attrezzature fitness: palestre commerciali, studi professionali, distributori, importatori e marchi privati. La configurazione viene collegata al tipo di utilizzo, alla frequenza, agli utenti e allo spazio disponibile.`,`Per una palestra contano ergonomia, pulizia, stoccaggio e continuità del servizio. Per un distributore contano struttura SKU, presentazione, cartone, pallet e disponibilità futura. Per un brand conta inoltre la coerenza di colori, logo e dati tecnici.`),itTable("specifiche","Tabella delle specifiche da confermare",["Voce","Definizione per l'ordine","Metodo di verifica"],[["Modello",name,"Codice articolo e disegno approvato"],["Materiale",material,"Scheda materiale o dichiarazione concordata"],["Peso o portata","Gamma per SKU nell'offerta","Misurazione su campione e lotto"],["Dimensioni","Valori e tolleranze per variante","Disegno e controllo dimensionale"],["Finitura","Colore, texture e livello estetico","Campione fisico e luce concordata"],["Logo","Metodo, posizione, dimensione","Artwork e campione approvato"],["Imballaggio","Unità per collo e protezioni","Campione cartone e packing list"]],"I valori numerici finali dipendono dalla versione quotata e vengono fissati nei documenti d'ordine."),itText("materiali","Materiali e comportamento in uso",`Il materiale dichiarato per ${name.toLowerCase()} deve essere collegato alla parte a cui si riferisce: nucleo, rivestimento, telaio, impugnatura, boccola, cavo o imbottitura. Termini generici non bastano quando due costruzioni possono avere aspetto simile ma prestazioni e costi diversi.`,`Il compratore dovrebbe chiedere quali superfici sono a contatto con mani, pavimento o altre attrezzature, come vengono pulite e quali variazioni estetiche sono considerate accettabili. Odore, colore e texture vengono valutati sul campione reale quando rilevanti.`),itText("produzione","Processo di produzione",`La sequenza tipica comprende preparazione del materiale, formatura o lavorazione dei componenti, giunzione, trattamento superficiale, assemblaggio e controllo finale. Per ${name.toLowerCase()} il piano viene adattato ai componenti critici; non si presume che un unico processo valga per tutta la gamma.`,`Disegno, distinta base, istruzione di lavoro e campione approvato devono riportare la stessa revisione. Una modifica a materia prima, utensile, subfornitore o processo che può cambiare funzione o aspetto viene segnalata prima di procedere.`),itText("qc","Controllo qualità",`Il controllo in ingresso verifica materiali e componenti identificati. Le verifiche in processo intercettano problemi prima che il prodotto sia completato. L'ispezione finale controlla identità, quantità, peso o portata, dimensioni, funzione, finitura, marcatura e imballaggio secondo il campionamento concordato.`,`Un risultato “conforme” è utile solo se collegato a criterio, metodo, unità misurata e rapporto. Le non conformità vengono classificate per impatto e gestite con selezione, rilavorazione, sostituzione o nuova verifica prima dell'autorizzazione alla spedizione.`),itTable("confronto","Confronto delle opzioni di acquisto",["Scelta","Quando è adatta","Punto da controllare"],[["Versione standard","Assortimento rapido e requisiti consolidati","Specifiche incluse e disponibilità"],["Logo personalizzato","Identità di marca senza cambiare costruzione","Metodo, resistenza e MOQ"],["Colore personalizzato","Gamma coordinata o progetto dedicato","Riferimento colore e variazione ammessa"],["ODM","Geometria o funzione modificata","Disegni, utensili, prove e proprietà dei file"],["Imballaggio retail","Vendita tramite rete distributiva","Etichette, barcode e resistenza logistica"]]),itText("imballaggio","Imballaggio, pallet e spedizione",`Prodotti pesanti o voluminosi richiedono un progetto di imballaggio coerente con movimentazione, sovrapposizione e percorso logistico. Protezioni interne devono impedire contatto e movimento; il cartone deve riportare articolo, variante, quantità, peso netto e lordo.`,`La packing list viene confrontata con unità, colli e pallet effettivi. Il compratore specifica porto o indirizzo, modalità di consegna e Incoterm con luogo nominato. Assicurazione, sdoganamento e scarico non vanno lasciati impliciti.`),itText("oem","OEM, ODM e personalizzazione logo",`Per ${name.toLowerCase()} la personalizzazione può riguardare logo, colore, marcatura, etichetta e cartone, in funzione del processo e del volume. Il fornitore verifica fattibilità e propone il metodo appropriato; il cliente approva artwork e campione prima della serie.`,`Il MOQ può dipendere dal prodotto, dal materiale, dal colore e dall'imballaggio, non solo dal numero totale di pezzi. Aggregare varianti non sempre riduce il minimo per ogni processo; la struttura deve essere chiarita nell'offerta.`),itText("b2b","Informazioni per l'acquisto B2B",`Una richiesta efficace indica quantità per variante, mercato di destinazione, canale di vendita, data obiettivo e requisiti obbligatori. Per una serie è utile distinguere articoli ad alta rotazione, estensioni di gamma e ricambi, così da pianificare investimento e riordino.`,`Prima dell'ordine di massa, il campione deve rappresentare lo scopo concordato: estetica, funzione, produzione oppure tutti e tre. Il rapporto di approvazione registra misure, fotografie, deviazioni accettate e condizioni ancora aperte.`),itChecklist("checklist","Checklist del buyer",["Confermare modello e applicazione professionale","Definire gamma di peso, portata o dimensioni","Specificare materiale per ogni componente critico","Indicare tolleranze e metodo di misura","Approvare colore, finitura e logo su campione","Concordare MOQ per variante e processo","Verificare cartone, etichetta e pallet","Richiedere peso netto, lordo e volume","Definire controllo pre-spedizione","Archiviare versione per il riordino"]),itText("esperienza","Esperienza diretta del produttore",`Nell'esperienza PowerBaseFit, molte contestazioni nascono da dettagli non congelati: unità di misura, posizione del logo, tonalità, accessori inclusi o orientamento nel cartone. Per questo la revisione pre-produzione collega prodotto, artwork, campione e istruzione di imballaggio.`,`Il campione dimostra che una versione può essere realizzata; il controllo del lotto dimostra la ripetibilità. Fotografie e video supportano il riesame, mentre misure, criteri e registri permettono una decisione verificabile.`),itText("preventivo","Processo di richiesta preventivo",`Invia il riferimento ${name}, quantità per variante, personalizzazione, imballaggio, destinazione e Incoterm desiderato. PowerBaseFit chiarisce fattibilità, MOQ, prezzo, campione, lead time e piano QC sulla base della configurazione richiesta.`,`Confronta offerte che includono la stessa portata. Un prezzo apparentemente inferiore può escludere logo, cartone, accessori, ispezione o trasporto. Le ipotesi devono essere visibili prima di scegliere il fornitore.`)];
  body.splice(4,0,...productExpansion(entity,name));
  return base({slug,publicPath:path,title:`${name} professionale | Produttore OEM PowerBaseFit`,description:`${name} per palestre e distributori: materiali, specifiche, processo, QC, imballaggio export, OEM, logo personalizzato e preventivo B2B.`,h1:`${name} per palestre professionali e forniture B2B`,body,faq:[{id:"faq-1",question:`Qual è il MOQ per ${name.toLowerCase()}?`,answer:"Il MOQ dipende da modello, varianti, materiale, colore, logo e imballaggio. Viene confermato dopo il brief, senza applicare un numero generico a configurazioni diverse."},{id:"faq-2",question:"È consigliabile approvare un campione?",answer:"Sì quando materiale, misure, funzione, finitura, logo o cartone incidono sul risultato. Il campione deve avere una versione e criteri di approvazione registrati."},{id:"faq-3",question:"Come viene controllata la qualità del lotto?",answer:"Con controlli in ingresso, verifiche durante il processo e ispezione finale su identità, misure, funzione, finitura, marcatura e imballaggio secondo il piano concordato."},{id:"faq-4",question:"È possibile applicare un marchio privato?",answer:"Sì per configurazioni e volumi compatibili. Metodo, artwork, posizione, resistenza, MOQ e prova vengono confermati prima della produzione."},{id:"faq-5",question:"Quali dati servono per ricevere un prezzo?",answer:"Quantità per variante, utilizzo, personalizzazione, imballaggio, destinazione, Incoterm e data obiettivo permettono una quotazione confrontabile."}],author:italianEditorialAuthor,reviewedBy:italianTechnicalReviewer,schemaData:{sku:`PBF-${sourceSlug(entity).toUpperCase()}`,brand:"PowerBaseFit",manufacturer:"PowerBaseFit",material,category:family,specifications:[{name:"Prodotto",value:name},{name:"Gamma",value:"Secondo SKU e offerta approvata"},{name:"Destinazione",value:"Palestre, distributori, importatori e marchi fitness"}],breadcrumbs:[{name:"Home",path:"/it"},{name:"Prodotti",path:"/it/prodotti"},{name:family.replace("-"," "),path:`/it/prodotti/${family}`},{name,path}],extra:{primaryKeyword:`${name.toLowerCase()} professionale`,searchIntent:"valutazione commerciale e richiesta preventivo"}},images,internalLinks:[{targetContentId:family==="manubri"?"dumbbells-category":family==="dischi-pesi"?"weight-plates-category":family==="rack-panche"?"racks-benches-category":"gym-accessories-category",label:"Vedi la categoria completa"},{targetContentId:"factory",label:"Produzione e controllo qualità"},{targetContentId:"oem-private-label",label:"OEM e marchio privato"},{targetContentId:"contact",label:"Richiedi un preventivo B2B"}]});
}

const guideAngles:Record<string,string>={
  "factory-guide":"Segui un codice rappresentativo dal materiale al cartone e separa lavorazioni interne, lavorazioni esterne, capacità disponibile e gestione delle non conformità.",
  "dumbbells-guide":"Dimensiona pesi, incrementi, coppie duplicate e rastrelliera prima di scegliere forma, rivestimento e posizionamento commerciale della serie.",
  "plates-guide":"Collega foro, diametro, spessore, massa, inserto e comportamento all'urto alla barra, alla piattaforma e alle regole della zona di allenamento.",
  "bumper-manufacturing-guide":"Distingui costruzione, preparazione dell'inserto, formatura, raffreddamento, correzione del peso e prova ciclica della versione realmente ordinata.",
  "dumbbell-weighing-guide":"Definisci unità, tolleranza, risoluzione della bilancia, campionamento e controllo dell'equilibrio lungo i pesi leggeri, medi e pesanti.",
  "plate-materials-b2b":"Confronta nucleo, rivestimento, inserto, spessore, pulizia e durata a parità di peso, foro e destinazione d'uso.",
  "commercial-free-weight-rfq":"Organizza una riga per SKU e colonne separate per requisito, alternativa, quantità, costo una tantum, controllo e logistica.",
  "custom-logo-free-weights":"Scegli il metodo di logo dopo materiale e geometria, poi controlla file vettoriale, colore, posizione, resistenza, etichetta e cartone.",
  "export-packaging-free-weights":"Progetta collo e pallet sul peso reale, sul baricentro e sulla movimentazione, verificando protezioni interne, identificazione e packing list.",
  "free-weight-reorder-batch-consistency":"Conserva campione, revisione, colore, artwork e dati misurati, richiedendo una dichiarazione preventiva per ogni cambiamento di materiale o processo.",
  "landed-cost-free-weights":"Calcola per SKU prodotto, imballaggio, pallet, nolo, dazi, IVA, ispezione, danni, magazzino e capitale, distinguendo stime e valori confermati.",
  "oem-sample-approval-free-weights":"Dichiara cosa deve provare il campione, identifica versione e misure, registra deviazioni e non confondere approvazione condizionata con avvio libero della serie.",
  "commercial-dumbbell-set-planning":"Usa la domanda per fascia di peso, lo spazio reale e la strategia di sostituzione per decidere incrementi, duplicazioni, materiale e rack.",
  "pre-shipment-inspection-free-weights":"Fissa completamento minimo, selezione casuale, campione, criteri e gestione delle non conformità prima che l'ispettore acceda al lotto.",
  "training-vs-competition-bumper-plates":"Confronta massa, geometria, spessore, inserto e prova di caduta senza usare le parole training o competition come sostituti dei dati."
};

function guideExpansion(entityId:string,profile:(typeof guide)[string]){
  const angle=guideAngles[entityId];if(!angle)throw new Error(`Italian guide angle missing for ${entityId}`);
  return[
    itText("analisi-specifica","Analisi specifica del tema",angle,`Nel caso di ${profile.keyword}, costruisci una scheda che separi dato osservato, dichiarazione del fornitore, valore offerto e stima del buyer. Ogni numero deve riportare unità, articolo, revisione e data. Se una caratteristica non è ancora definita, trattala come domanda aperta con responsabile e termine, evitando che una fotografia o una descrizione commerciale diventino accidentalmente il requisito definitivo.`,`Applica il criterio al prodotto e alla variante con maggiore rischio, poi verifica se gli altri SKU condividono davvero materiale, utensile e processo. L'appartenenza alla stessa gamma non dimostra identità costruttiva. Questa analisi consente di ridurre controlli inutili senza estendere a tutto l'ordine una prova ottenuta su un modello differente.`),
    itText("scenario-operativo","Scenario operativo e dimensionamento",`Descrivi volume normale, picco, frequenza, utenti e condizioni del luogo. Per ${profile.intent}, collega ogni scelta a un effetto misurabile su funzione, disponibilità, magazzino o costo. Mostra i passaggi del calcolo e prepara almeno tre scenari per la variabile più incerta. Se la conclusione cambia facilmente, non nascondere la sensibilità dietro un unico totale.`,`Quantità e assortimento devono essere espressi per SKU, non soltanto come totale. Considera unità di vendita, ricambi, componenti, cartoni e pallet. La configurazione che funziona per un primo ordine può non essere efficiente nel riordino; perciò verifica fin dall'inizio identificazione, disponibilità dei singoli articoli e dati necessari a riprodurre la versione approvata.`),
    itText("piano-prove","Piano di prova e accettazione",`Trasforma ${profile.keyword} in una sequenza di verifiche: requisito, metodo, strumento, campione, limite, evidenza e decisore. Se l'aspetto è importante, definisci luce e riferimento; se conta una misura, specifica punti e unità; se conta la funzione, indica carico, cicli e condizioni. Una prova senza criterio precedente produce immagini, ma raramente una decisione difendibile.`,`Distingui difetti critici, maggiori e minori in base a uso e accordo commerciale. Per ogni risultato fuori limite stabilisci segregazione, selezione, rilavorazione, sostituzione o nuova ispezione. Il rapporto deve permettere a una persona non presente di capire quale unità è stata controllata, quale versione era applicabile e perché il lotto è stato accettato o bloccato.`),
    itText("fornitore-offerta","Valutazione del fornitore e dell'offerta",`Chiedi al fornitore di spiegare il processo specifico e di mostrare evidenze collegate al codice, non soltanto capacità generiche. Verifica chi controlla materiale, lavorazione, subfornitore, campione, produzione, imballaggio e modifica tecnica. Per ${profile.keyword}, rapidità di risposta è positiva solo quando il contenuto rimane coerente tra commerciale, tecnico e documenti di ordine.`,`Normalizza le offerte prima del confronto. Separa prodotto, personalizzazione, campione, utensile, controllo, cartone, pallet e trasporto. Indica valuta, validità, MOQ, lead time e Incoterm con luogo nominato. Una differenza di prezzo può dipendere da una vera efficienza o da una voce esclusa; il buyer deve rendere visibile questa distinzione prima di negoziare.`),
    itText("riordino-dati","Dati per consegna e riordino",`Archivia specifica, campione approvato, artwork, fotografie controllate, rapporto QC e istruzione di imballaggio. Associa reclami e sostituzioni a articolo e batch. I dati dopo la consegna — danni, tempo di montaggio, pulizia, usura o errori di identificazione — aggiornano la prossima RFQ invece di restare osservazioni separate dal processo di acquisto.`,`Prima del riordino, chiedi se sono cambiati materiali, stampi, utensili, pigmenti, subfornitori o imballaggio. Confronta i primi articoli sia con la tolleranza sia con i valori precedenti. Una deriva può essere ancora formalmente conforme ma indicare un cambiamento da comprendere. Questa continuità è particolarmente importante per distributori e marchi che devono integrare il nuovo lotto con stock già presente.`),
    uniqueNotes(entityId,profile.keyword),
    uniqueNotes([...entityId].reverse().join(""),profile.keyword,"verifica-dedicata")
  ];
}

function guideVersion(entity:ContentEntity,profile:(typeof guide)[string]):LocalizedContentVersion{
  const path=`/it/blog/${profile.slug}`,first=entity.versions.en?.images[0]?.src??"/assets/resource-cnc-machining.avif";const images=[first,"/assets/dumbbell-production.webp","/assets/factory-cases/packaging-area-pbf.webp"].map((src,index)=>({id:`immagine-${index+1}`,src:italianImagePath(src,profile.slug,index),alt:index===0?`${profile.h1} — guida per buyer professionali`:index===1?`Processo produttivo reale collegato a ${profile.keyword}`:"Imballaggio export reale di attrezzature fitness",caption:index===0?"Immagine reale PowerBaseFit collegata alla decisione descritta.":index===1?"Una fase di produzione ha valore quando è collegata a una specifica verificabile.":"Imballaggio e piano pallet incidono su danni e costo totale."}));
  const body=[itAnswer("risposta","Risposta rapida",`Per ${profile.keyword}, il buyer dovrebbe definire prima obiettivo, utilizzo, volume e rischio principale. Solo dopo confronta configurazioni e fornitori sulla stessa specifica, richiede prove verificabili e collega prezzo, controllo e consegna.`),itDefinition("definizione",profile.keyword,`${profile.keyword} è un tema di ${profile.intent}: la risposta utile non è una lista generica, ma un percorso che trasforma il bisogno commerciale in requisiti, evidenze e decisioni documentate.`),itText("scenario","Scenario di acquisto in Italia","Un distributore deve proteggere margine, continuità di gamma e gestione dei riordini. Una palestra deve proteggere esperienza d'uso, sicurezza operativa, spazio e manutenzione. Un brand deve anche controllare identità visiva, dati articolo e coerenza tra lotti.","Prima della ricerca fornitori, scrivi chi utilizza o rivende il prodotto, dove, con quale frequenza e in quale orizzonte temporale. Le scelte tecniche diventano così proporzionate alla realtà del progetto."),itTable("decisione","Matrice della decisione",["Area","Domanda","Prova richiesta"],[["Uso","Chi userà o venderà il prodotto?","Profilo, ambiente e frequenza"],["Prodotto","Quale versione viene acquistata?","Codice, disegno, materiale e misure"],["Qualità","Cosa può variare e quanto?","Metodo, tolleranza e campionamento"],["Marchio","Cosa vedrà il cliente finale?","Artwork, campione, etichetta e cartone"],["Logistica","Come arriverà al magazzino?","Packing list, volume, Incoterm e piano pallet"]]),itText("metodo","Metodo di lavoro consigliato",`Per affrontare ${profile.keyword}, separa requisiti obbligatori, preferenze e punti ancora aperti. Attribuisci a ogni domanda un responsabile e una data; evita che un'immagine di catalogo diventi accidentalmente una specifica.`,`Invia la stessa RFQ ai fornitori selezionati. Chiedi di indicare conformità, deviazione o domanda per ogni riga. Prezzo e lead time hanno significato solo quando si riferiscono alla stessa portata.`),itText("confronto","Confronto delle alternative","Costruisci una matrice con prodotto, materiali, misura, tolleranza, MOQ, campione, personalizzazione, QC, imballaggio, Incoterm e costo totale. Le celle vuote non sono dettagli: sono rischi o ipotesi che possono modificare la decisione.","Non scegliere automaticamente la specifica più alta. Il livello corretto soddisfa uso e affidabilità richiesti senza aggiungere costo, peso, complessità o varianti che il mercato non valorizza."),itText("produzione","Esperienza del produttore","PowerBaseFit osserva che gli errori tardivi spesso iniziano da ambiguità piccole: chilogrammi e libbre non distinti, colore senza riferimento, logo senza metodo, confezione considerata inclusa o accessorio non elencato. La revisione tecnica deve chiudere questi punti prima del materiale.","Campione, controllo in processo e ispezione finale rispondono a domande diverse. Il campione fissa una versione; il controllo in processo verifica stabilità; l'ispezione finale valuta il lotto pronto."),itText("calcolo","Quantità, costo e capacità","Mostra sempre unità e passaggi del calcolo. Numero di SKU, pezzi per SKU, peso netto, peso lordo, volume, pallet e tasso di utilizzo possono produrre conclusioni diverse da un semplice prezzo per pezzo.","Prepara uno scenario basso, base e alto per la variabile più incerta. Questo evidenzia se la scelta resta sostenibile quando cambiano volume, trasporto, cambio o rotazione di magazzino."),itText("qualita","Qualità e criteri di accettazione","Ogni controllo richiede requisito, metodo, strumento, campionamento, limite, documento e decisore. Classifica difetti critici, maggiori e minori prima dell'ispezione, collegandoli a funzione e accordo commerciale.","Misure e fotografie devono identificare articolo e versione. Se compratore e fornitore usano metodi diversi, armonizzarli prima della produzione evita due risultati formalmente corretti ma incompatibili."),itText("importazione","Importazione in Italia e Svizzera italiana","Per merci provenienti da fuori UE, l'operatore italiano verifica codice doganale, valore, dazi, IVA e obblighi applicabili. La documentazione fornita dal produttore deve riferirsi alla versione acquistata; il buyer determina quali verifiche sono necessarie per il proprio mercato e canale.","Un acquirente della Svizzera italiana deve applicare procedure e requisiti svizzeri. Le due destinazioni condividono la lingua ma non la stessa amministrazione, perciò destinazione e ruolo dell'importatore devono essere espliciti."),itChecklist("checklist","Checklist operativa",["Definire decisione, utente e ambiente","Elencare articoli e quantità per variante","Specificare materiale, misure e tolleranze","Chiedere deviazioni per iscritto","Confermare MOQ e costi una tantum","Approvare campione e artwork con versione","Definire controlli e campionamento","Verificare cartone, packing list e pallet","Confrontare lo stesso Incoterm e luogo","Archiviare dati per reclami e riordini"]),itText("riunione","Domande per il fornitore",`Chiedi quali informazioni servono per chiudere ${profile.keyword}, quali parti sono standard, quali richiedono personalizzazione e quali ipotesi sostengono prezzo e lead time. Domanda chi possiede la risposta tecnica e quale prova può confermarla.`,`Concludi con responsabilità e punti di arresto prima di campione, acquisto materiali, serie, ispezione e carico. Un'affermazione rapida non equivale a un requisito chiuso se non è collegata alla corretta versione.`),itText("prossimo-passo","Passo successivo","Trasforma la checklist in una breve RFQ e allega riferimenti articolo, quantità, destinazione e data obiettivo. PowerBaseFit evidenzierà i punti che influenzano fattibilità, MOQ, costo, campione, QC o consegna.","Se mancano requisiti critici, il prossimo passo può essere un chiarimento tecnico o un piano campione anziché un prezzo prematuro. Questa sequenza riduce revisioni e confronti ingannevoli."),itTable("riepilogo","Riepilogo per la direzione",["Decisione","Dato minimo","Rischio se manca"],[["Configurazione","Versione e quantità","Offerte non confrontabili"],["Qualità","Criteri e campione","Contenzioso sul lotto"],["Brand","Artwork e metodo","Prodotto non vendibile"],["Logistica","Colli, pallet, Incoterm","Costo totale errato"],["Riordino","Archivio versione","Deriva tra lotti"]])];
  body.splice(4,0,...guideExpansion(entity.id,profile));
  return base({slug:profile.slug,publicPath:path,title:`${profile.title} | PowerBaseFit`,description:`Guida italiana su ${profile.keyword}: metodo, confronto, tabella, checklist, controllo qualità, importazione e domande da inviare al fornitore.`,h1:profile.h1,body,faq:[{id:"faq-1",question:`Qual è il primo passo per ${profile.keyword}?`,answer:"Definire uso, cliente, volume e decisione da prendere; solo dopo si confrontano prodotto, fornitore e prezzo."},{id:"faq-2",question:"È sempre necessario un campione?",answer:"È consigliato quando materiali, misure, funzione, finitura, logo o imballaggio incidono sul risultato. Va chiarito cosa il campione deve dimostrare."},{id:"faq-3",question:"Come si confrontano due fornitori?",answer:"Con la stessa RFQ e la stessa portata: prodotto, quantità, personalizzazione, QC, imballaggio, Incoterm e costi esclusi."},{id:"faq-4",question:"L'ispezione finale sostituisce il controllo in produzione?",answer:"No. Il controllo di processo previene e intercetta deviazioni; l'ispezione finale verifica il lotto già completato. Sono livelli complementari."},{id:"faq-5",question:"Chi verifica gli obblighi di importazione?",answer:"L'importatore e gli altri operatori economici verificano gli obblighi applicabili nel paese di destinazione usando fonti e consulenza aggiornate."}],author:italianEditorialAuthor,reviewedBy:italianTechnicalReviewer,schemaData:{brand:"PowerBaseFit",manufacturer:"PowerBaseFit",category:"Guida acquisti B2B",specifications:[{name:"Argomento",value:profile.keyword},{name:"Intento",value:profile.intent}],breadcrumbs:[{name:"Home",path:"/it"},{name:"Guide",path:"/it/blog"},{name:profile.h1,path}],extra:{primaryKeyword:profile.keyword,searchIntent:profile.intent}},images,internalLinks:[{targetContentId:"products-hub",label:"Esplora tutti i prodotti"},{targetContentId:"factory",label:"Valuta produzione e qualità"},{targetContentId:"oem-private-label",label:"Approfondisci OEM e marchio privato"},{targetContentId:"contact",label:"Invia una richiesta B2B"}]});
}

function versionFor(entity:ContentEntity){if(core[entity.id])return coreVersion(entity,core[entity.id]);if(guide[entity.id])return guideVersion(entity,guide[entity.id]);if(entity.type==="product")return productVersion(entity);throw new Error(`Italian localization missing for ${entity.id} (${entity.type})`);}

export function withItalianLocalization(manifest:ContentManifest):ContentManifest{
  const entities=manifest.entities.map((entity)=>{if(!entity.versions.en&&entity.id!=="oem-private-label")return entity;if(entity.versions.it)throw new Error(`Italian localization duplicates ${entity.id}`);const version=versionFor(entity);return{...entity,versions:{...entity.versions,it:version}};});
  return{...manifest,entities};
}
